import { useEffect, useMemo, useState } from 'react';
import { useTranslation } from 'react-i18next';

import { Text } from '@actual-app/components/text';
import { theme } from '@actual-app/components/theme';
import { View } from '@actual-app/components/view';

import { send } from 'loot-core/platform/client/connection';
import { getCurrency } from 'loot-core/shared/currencies';
import { q } from 'loot-core/shared/query';
import { integerToAmount } from 'loot-core/shared/util';
import type { AccountEntity, CurrencyWidget } from 'loot-core/types/models';

import { ReportCard } from '../ReportCard';
import { ReportCardName } from '../ReportCardName';
import { useDashboardWidgetCopyMenu } from '../useDashboardWidgetCopyMenu';

type CurrencyBalance = {
  currency: string;
  balance: number;
  accountCount: number;
  accounts: Array<{ id: string; name: string; balance: number }>;
};

type MultiCurrencyCardProps = {
  widgetId: string;
  isEditing?: boolean;
  accounts: AccountEntity[];
  meta?: CurrencyWidget['meta'];
  onMetaChange: (newMeta: CurrencyWidget['meta']) => void;
  onRemove: () => void;
  onCopy: (targetDashboardId: string) => void;
};

function formatCurrencyAmount(amount: number, currencyCode: string): string {
  const currency = getCurrency(currencyCode);
  // Convert from integer (cents) to decimal
  const decimalAmount = integerToAmount(amount, 2);

  // Format the number
  const absAmount = Math.abs(decimalAmount);
  let formatted: string;

  // Simple formatting based on decimal places
  if (currency.decimalPlaces === 0) {
    formatted = Math.round(absAmount).toLocaleString();
  } else {
    formatted = absAmount.toLocaleString(undefined, {
      minimumFractionDigits: currency.decimalPlaces,
      maximumFractionDigits: currency.decimalPlaces,
    });
  }

  // Add symbol
  const sign = amount < 0 ? '-' : '';
  if (currency.symbolFirst) {
    return `${sign}${currency.symbol}${formatted}`;
  } else {
    return `${sign}${formatted} ${currency.symbol}`;
  }
}

function CurrencyRow({
  currency,
  balance,
  accountCount,
}: {
  currency: string;
  balance: number;
  accountCount: number;
}) {
  const { t } = useTranslation();
  const isPositive = balance > 0;
  const isNegative = balance < 0;

  return (
    <View
      style={{
        flexDirection: 'row',
        justifyContent: 'space-between',
        alignItems: 'center',
        padding: '8px 0',
        borderBottom: `1px solid ${theme.tableBorder}`,
      }}
    >
      <View style={{ flexDirection: 'column' }}>
        <Text
          style={{
            fontWeight: 600,
            fontSize: 14,
            color: theme.pageText,
          }}
        >
          {currency}
        </Text>
        <Text
          style={{
            fontSize: 11,
            color: theme.pageTextSubdued,
          }}
        >
          {t('{{count}} account', { count: accountCount })}
        </Text>
      </View>
      <Text
        style={{
          fontWeight: 600,
          fontSize: 14,
          color: isPositive
            ? theme.noticeTextLight
            : isNegative
              ? theme.errorText
              : theme.pageText,
        }}
      >
        {formatCurrencyAmount(balance, currency)}
      </Text>
    </View>
  );
}

export function MultiCurrencyCard({
  widgetId,
  isEditing,
  accounts,
  meta = {},
  onMetaChange,
  onRemove,
  onCopy,
}: MultiCurrencyCardProps) {
  const { t } = useTranslation();
  const [nameMenuOpen, setNameMenuOpen] = useState(false);
  const [accountBalances, setAccountBalances] = useState<Map<string, number>>(
    new Map(),
  );
  const [isLoading, setIsLoading] = useState(true);

  const { menuItems: copyMenuItems, handleMenuSelect: handleCopyMenuSelect } =
    useDashboardWidgetCopyMenu(onCopy);

  const { name, includeOffBudget = true } = meta || {};

  // Fetch account balances
  useEffect(() => {
    async function fetchBalances() {
      setIsLoading(true);
      const balances = new Map<string, number>();

      const activeAccounts = accounts.filter(
        acc => !acc.closed && !acc.tombstone,
      );

      // Fetch balance for each account
      for (const account of activeAccounts) {
        try {
          const query = q('transactions')
            .filter({ account: account.id })
            .options({ splits: 'none' })
            .calculate({ $sum: '$amount' });
          const { data } = await send('query', query.serialize());
          balances.set(account.id, data || 0);
        } catch (e) {
          console.error(`Failed to fetch balance for account ${account.id}`, e);
          balances.set(account.id, 0);
        }
      }

      setAccountBalances(balances);
      setIsLoading(false);
    }

    void fetchBalances();
  }, [accounts]);

  const currencyBalances = useMemo(() => {
    const currencyMap = new Map<string, CurrencyBalance>();

    for (const account of accounts) {
      if (account.closed || account.tombstone) continue;
      if (!includeOffBudget && account.offbudget) continue;

      const currency = account.currency || 'USD';
      const balance = accountBalances.get(account.id) || 0;

      const existing = currencyMap.get(currency) || {
        currency,
        balance: 0,
        accountCount: 0,
        accounts: [],
      };

      existing.balance += balance;
      existing.accountCount += 1;
      existing.accounts.push({
        id: account.id,
        name: account.name,
        balance,
      });

      currencyMap.set(currency, existing);
    }

    return Array.from(currencyMap.values()).sort((a, b) =>
      a.currency.localeCompare(b.currency),
    );
  }, [accounts, accountBalances, includeOffBudget]);


  return (
    <ReportCard
      isEditing={isEditing}
      menuItems={[
        {
          name: 'rename',
          text: t('Rename'),
        },
        {
          name: 'toggle-offbudget',
          text: includeOffBudget
            ? t('Exclude off-budget accounts')
            : t('Include off-budget accounts'),
        },
        {
          name: 'remove',
          text: t('Remove'),
        },
        ...copyMenuItems,
      ]}
      onMenuSelect={item => {
        if (handleCopyMenuSelect(item)) return;
        switch (item) {
          case 'rename':
            setNameMenuOpen(true);
            break;
          case 'toggle-offbudget':
            onMetaChange({
              ...meta,
              includeOffBudget: !includeOffBudget,
            });
            break;
          case 'remove':
            onRemove();
            break;
          default:
            break;
        }
      }}
    >
      <View style={{ flex: 1, padding: 16 }}>
        <ReportCardName
          name={name || t('Currencies')}
          isEditing={nameMenuOpen}
          onChange={(newName: string) => {
            onMetaChange({ ...meta, name: newName });
            setNameMenuOpen(false);
          }}
          onClose={() => setNameMenuOpen(false)}
        />

        <View style={{ flex: 1, marginTop: 12, overflow: 'auto' }}>
          {isLoading ? (
            <View
              style={{
                flex: 1,
                justifyContent: 'center',
                alignItems: 'center',
              }}
            >
              <Text style={{ color: theme.pageTextSubdued }}>
                {t('Loading...')}
              </Text>
            </View>
          ) : currencyBalances.length === 0 ? (
            <View
              style={{
                flex: 1,
                justifyContent: 'center',
                alignItems: 'center',
              }}
            >
              <Text style={{ color: theme.pageTextSubdued }}>
                {t('No accounts found')}
              </Text>
            </View>
          ) : (
            <View style={{ gap: 0 }}>
              {currencyBalances.map(cb => (
                <CurrencyRow
                  key={cb.currency}
                  currency={cb.currency}
                  balance={cb.balance}
                  accountCount={cb.accountCount}
                />
              ))}
            </View>
          )}
        </View>

        {currencyBalances.length > 1 && (
          <View
            style={{
              marginTop: 12,
              paddingTop: 8,
              borderTop: `2px solid ${theme.tableBorder}`,
            }}
          >
            <Text
              style={{
                fontSize: 11,
                color: theme.pageTextSubdued,
                textAlign: 'center',
              }}
            >
              {t('{{currencyCount}} currencies across {{accountCount}} accounts', {
                currencyCount: currencyBalances.length,
                accountCount: currencyBalances.reduce(
                  (sum, c) => sum + c.accountCount,
                  0,
                ),
              })}
            </Text>
          </View>
        )}
      </View>
    </ReportCard>
  );
}
